// Recursive Subdivisions - Geometric Composition Engine

let cells = [];
let prevParams = '';
let seed = 42;

const PALETTES = {
  mondrian: [[255,0,0],[0,0,255],[255,255,0],[255,255,255],[0,0,0]],
  bauhaus: [[229,53,44],[0,113,188],[249,193,22],[255,255,255],[30,30,30]],
  pastel: [[255,179,186],[255,223,186],[255,255,186],[186,255,201],[186,225,255]],
  neon: [[255,0,110],[0,255,163],[191,0,255],[0,200,255],[255,240,0]],
  earth: [[139,90,43],[85,107,47],[160,82,45],[210,180,140],[60,60,40]],
  monochrome: [[30,30,30],[80,80,80],[140,140,140],[200,200,200],[245,245,245]],
  jewel: [[0,100,0],[75,0,130],[139,0,0],[0,0,139],[184,134,11]],
  frost: [[200,220,240],[170,200,230],[220,235,245],[140,180,220],[240,248,255]]
};

function seededRandom() {
  seed = (seed * 16807 + 0) % 2147483647;
  return (seed - 1) / 2147483646;
}

function getDepthCount(v) {
  const m = {shallow:2, moderate:3, deep:4, extreme:5, fractal:6, infinite:7};
  return m[v] || 3;
}

function getGap(v) {
  const m = {none:0, hairline:1, thin:2, medium:4, wide:8, chunky:14};
  return m[v] || 2;
}

function getSplitRatio(v) {
  if (v === 'equal') return 0.5;
  if (v === 'golden') return 0.618;
  if (v === 'thirds') return 0.333;
  if (v === 'asymmetric') return 0.8;
  if (v === 'chaotic') return 0.15 + seededRandom() * 0.7;
  return 0.3 + seededRandom() * 0.4;
}

function getCornerRadius(v, size) {
  const s = Math.min(size, 40);
  const m = {sharp:0, rounded:s*0.3, chamfered:s*0.15, organic:s*0.5, notched:s*0.1, mixed:s*0.2};
  return m[v] || 0;
}

function getFillProb(v) {
  const m = {sparse:0.3, balanced:0.55, dense:0.75, packed:0.9, overflow:1.0, minimal:0.15};
  return m[v] || 0.55;
}

function subdivide(x, y, w, h, depth, maxDepth, bias, orient) {
  if (depth >= maxDepth || w < 12 || h < 12) {
    cells.push({x:x, y:y, w:w, h:h, depth:depth});
    return;
  }
  let horizontal;
  if (orient === 'horizontal') horizontal = true;
  else if (orient === 'vertical') horizontal = false;
  else if (orient === 'alternating') horizontal = depth % 2 === 0;
  else if (orient === 'diagonal') horizontal = (x + y) % 2 === 0 ? depth % 2 === 0 : depth % 2 === 1;
  else if (orient === 'radial') horizontal = seededRandom() > 0.5;
  else if (orient === 'spiral') horizontal = (depth + Math.floor(x / 100)) % 2 === 0;
  else horizontal = seededRandom() > 0.5;

  let ratio = getSplitRatio(bias);
  if (bias === 'random' || bias === 'chaotic') ratio = 0.25 + seededRandom() * 0.5;

  if (horizontal) {
    let split = y + h * ratio;
    subdivide(x, y, w, split - y, depth + 1, maxDepth, bias, orient);
    subdivide(x, split, w, y + h - split, depth + 1, maxDepth, bias, orient);
  } else {
    let split = x + w * ratio;
    subdivide(x, y, split - x, h, depth + 1, maxDepth, bias, orient);
    subdivide(split, y, x + w - split, h, depth + 1, maxDepth, bias, orient);
  }
}

p.setup = function() {
  p.createCanvas(600, 600);
  p.frameRate(30);
};

p.draw = function() {
  let depthV = p.getSynthVar('subdivision_depth') || 'moderate';
  let biasV = p.getSynthVar('split_bias') || 'golden';
  let gapV = p.getSynthVar('gap_width') || 'thin';
  let fillV = p.getSynthVar('fill_strategy') || 'solid';
  let palV = p.getSynthVar('color_palette') || 'mondrian';
  let densV = p.getSynthVar('fill_density') || 'balanced';
  let cornV = p.getSynthVar('corner_style') || 'sharp';
  let orientV = p.getSynthVar('orientation') || 'alternating';
  let bordV = p.getSynthVar('border_style') || 'thin';
  let animV = p.getSynthVar('animation') || 'static';

  let params = depthV + biasV + gapV + orientV + densV + fillV + palV + cornV + bordV + animV;
  if (params !== prevParams || animV === 'shuffle') {
    prevParams = params;
    seed = 42;
    cells = [];
    let gap = getGap(gapV);
    subdivide(gap, gap, 600 - gap * 2, 600 - gap * 2, 0, getDepthCount(depthV), biasV, orientV);
  }

  if (animV !== 'static') p.frameRate(30); else p.frameRate(10);

  let palette = PALETTES[palV] || PALETTES.mondrian;
  let gap = getGap(gapV);
  let fillProb = getFillProb(densV);

  p.background(gap > 0 ? 20 : 240);

  for (let i = 0; i < cells.length; i++) {
    let c = cells[i];
    let cx = c.x + gap / 2;
    let cy = c.y + gap / 2;
    let cw = c.w - gap;
    let ch = c.h - gap;
    if (cw < 2 || ch < 2) continue;

    let cr = getCornerRadius(cornV, Math.min(cw, ch));
    seed = i * 7 + 13;
    let fillIt = seededRandom() < fillProb;
    let colIdx = Math.floor(seededRandom() * palette.length);
    let col = palette[colIdx];
    let col2Idx = (colIdx + 1 + Math.floor(seededRandom() * (palette.length - 1))) % palette.length;
    let col2 = palette[col2Idx];

    // Animation effects
    let animAlpha = 255;
    let animScale = 1;
    if (animV === 'pulse') {
      animAlpha = 150 + 105 * Math.sin(p.frameCount * 0.03 + i * 0.5);
    } else if (animV === 'breathe') {
      animScale = 0.92 + 0.08 * Math.sin(p.frameCount * 0.02 + i * 0.3);
    } else if (animV === 'grow') {
      let t = Math.min(1, p.frameCount * 0.005);
      let cellT = Math.max(0, t * cells.length - i) / 1;
      cellT = Math.min(1, cellT);
      animScale = cellT;
    } else if (animV === 'glitch') {
      if (Math.sin(p.frameCount * 0.1 + i * 17) > 0.92) {
        cx += (seededRandom() - 0.5) * 10;
        cy += (seededRandom() - 0.5) * 10;
      }
    } else if (animV === 'shuffle' && p.frameCount % 60 === 0) {
      seed = Math.floor(Math.random() * 10000);
      cells = [];
      subdivide(gap, gap, 600 - gap * 2, 600 - gap * 2, 0, getDepthCount(depthV), biasV, orientV);
      prevParams = '';
    }

    p.push();
    p.translate(cx + cw / 2, cy + ch / 2);
    p.scale(animScale);
    p.translate(-cw / 2, -ch / 2);

    // Border
    if (bordV === 'none') {
      p.noStroke();
    } else if (bordV === 'thin') {
      p.stroke(0, 0, 0, animAlpha); p.strokeWeight(1);
    } else if (bordV === 'bold') {
      p.stroke(0, 0, 0, animAlpha); p.strokeWeight(3);
    } else if (bordV === 'double') {
      p.stroke(0, 0, 0, animAlpha); p.strokeWeight(1);
      p.noFill(); p.rect(- 2, -2, cw + 4, ch + 4, cr);
    } else if (bordV === 'shadow') {
      p.noStroke();
      p.fill(0, 0, 0, 40);
      p.rect(3, 3, cw, ch, cr);
    } else if (bordV === 'glow') {
      p.noStroke();
      p.fill(col[0], col[1], col[2], 30);
      p.rect(-4, -4, cw + 8, ch + 8, cr + 4);
    }

    if (bordV !== 'none' && bordV !== 'shadow' && bordV !== 'glow') {
      p.stroke(0, 0, 0, animAlpha * 0.8);
    } else if (bordV === 'none') {
      p.noStroke();
    }

    if (!fillIt && fillV !== 'empty') {
      p.fill(240, 240, 240, animAlpha);
      p.rect(0, 0, cw, ch, cr);
    } else if (fillV === 'solid') {
      p.fill(col[0], col[1], col[2], animAlpha);
      p.rect(0, 0, cw, ch, cr);
    } else if (fillV === 'gradient') {
      p.noStroke();
      let steps = Math.max(2, Math.floor(ch / 4));
      for (let s = 0; s < steps; s++) {
        let t = s / steps;
        let r = col[0] + (col2[0] - col[0]) * t;
        let g = col[1] + (col2[1] - col[1]) * t;
        let b = col[2] + (col2[2] - col[2]) * t;
        p.fill(r, g, b, animAlpha);
        let sy = s * ch / steps;
        let sh = ch / steps + 1;
        p.rect(0, sy, cw, sh, s === 0 ? cr : 0, s === 0 ? cr : 0, s === steps - 1 ? cr : 0, s === steps - 1 ? cr : 0);
      }
    } else if (fillV === 'striped') {
      p.fill(col[0], col[1], col[2], animAlpha);
      p.rect(0, 0, cw, ch, cr);
      p.fill(col2[0], col2[1], col2[2], animAlpha * 0.6);
      let stripeW = Math.max(3, cw / 8);
      for (let sx = stripeW; sx < cw; sx += stripeW * 2) {
        p.rect(sx, 0, stripeW, ch);
      }
    } else if (fillV === 'dotted') {
      p.fill(col[0], col[1], col[2], animAlpha);
      p.rect(0, 0, cw, ch, cr);
      p.fill(col2[0], col2[1], col2[2], animAlpha * 0.5);
      p.noStroke();
      let dotR = Math.max(2, Math.min(cw, ch) / 8);
      for (let dx = dotR; dx < cw - dotR; dx += dotR * 2.5) {
        for (let dy = dotR; dy < ch - dotR; dy += dotR * 2.5) {
          p.circle(dx, dy, dotR);
        }
      }
    } else if (fillV === 'textured') {
      p.fill(col[0], col[1], col[2], animAlpha);
      p.rect(0, 0, cw, ch, cr);
      for (let tx = 0; tx < cw; tx += 3) {
        for (let ty = 0; ty < ch; ty += 3) {
          let n = p.noise(tx * 0.1 + i, ty * 0.1);
          if (n > 0.5) {
            p.fill(col2[0], col2[1], col2[2], animAlpha * n * 0.4);
            p.rect(tx, ty, 2, 2);
          }
        }
      }
    } else {
      p.noFill();
      p.stroke(col[0], col[1], col[2], animAlpha * 0.5);
      p.strokeWeight(1);
      p.rect(0, 0, cw, ch, cr);
    }

    p.pop();
  }
};
